pure fn deduplicate(items: [Number]) -> [Number] {
    result = []
    for item in items {
        if not (item in result) { result = append(result, item) }
    }
    return result
}
entry main(x: Text) { return deduplicate([1, 3, 2, 3, 1, 4, 2, 5]) }

pure fn deduplicate(items: [Text]) -> [Text] {
    result = []
    for item in items {
        if not (item in result) { result = append(result, item) }
    }
    return result
}
entry main(x: Text) {
    return deduplicate(["apple", "banana", "apple", "cherry", "banana"])
}

pure fn count_char(s: Text, ch: Text) -> Number {
    count = 0
    for c in split(s, "") {
        if c == ch { count = count + 1 }
    }
    return count
}
pure fn unique_sorted(s: Text) -> [Text] {
    result = []
    for c in split(s, "") {
        if not (c in result) { result = append(result, c) }
    }
    return sort(result)
}
entry main(x: Text) {
    s = "hello"
    chars = unique_sorted(s)
    pairs = []
    for c in chars {
        pairs = append(pairs, join([c, ":", to_text(count_char(s, c))], ""))
    }
    return join(pairs, ", ")
}

pure fn fib(n: Number) -> Number {
    if n <= 1 { return n }
    return fib(n - 1) + fib(n - 2)
}
entry main(x: Text) {
    results = []
    for i in range(0, 8) {
        results = append(results, to_text(fib(i)))
    }
    return join(results, ", ")
}

