pure fn name_key(pair: Text) -> Text {
    return get(split(pair, ":"), 0)
}
entry main(x: Text) {
    pairs = ["Charlie:78", "Alice:85", "Bob:92"]
    return join(sort(pairs, name_key), ", ")
}

intent label_score(name: Text, score: Text) -> Text {
    goal: pass_or_fail
}
pure fn parse_pair(pair: Text) -> [Text] {
    return split(trim(pair), ":")
}
entry main(x: Text) {
    pairs = split("Alice:85,Bob:62,Carol:91", ",")
    results = []
    for pair in pairs {
        parts = parse_pair(pair)
        name = get(parts, 0)
        score = get(parts, 1)
        results = append(results, join([name, ": ", label_score(name, score)], ""))
    }
    return join(results, ", ")
}

intent classify_item(item: Text) -> Text {
    goal: food_vehicle_or_nature
}
pure fn parse_items(s: Text) -> [Text] {
    result = []
    for item in split(s, ",") {
        result = append(result, trim(item))
    }
    return result
}
entry main(x: Text) {
    items = parse_items("apple,car,ocean")
    results = []
    for item in items {
        results = append(results, join([item, ": ", classify_item(item)], ""))
    }
    return join(results, "\n")
}

